<template>
  <!-- ==============================================
    ** Inner Banner **
    =================================================== -->
  <div class="inner-banner blog">
    <div class="container">
      <div class="row">
        <div class="col-sm-12">
          <div class="content">
            <h1>EVENTOS RECIENTES DE LA CARRERA</h1>

            <h4>
                  <router-link to="/">INICIO</router-link>
                </h4>
   
                <h3> OFERTAS ACADÉMICAS </h3>
          </div>
        </div>
      </div>
    </div>
  </div>

  <!-- ==============================================
    ** Blog **
    =================================================== -->
  <div class="container blog-wrapper padding-lg">
    <div class="row">
      <div class="col-12" v-if="Eventos.length == 0">
        <h2>SIN EVENTOS</h2>
      </div>

      <!-- Start Left Column -->
      <div
        class="col-sm-8 blog-left"
        v-for="(ev, id_ev) of Eventos"
        :key="id_ev"
      >

      <div class="left-aligned">
        <ul class="blog-listing">
          <li>
            <!-- <router-link :to="'/detalleEvento/' + ev.evento_id"> -->
            <img
              :src="url_api + '/Eventos/' + ev.evento_imagen"
              class="img-responsive"
              alt=""
            />
            <!-- </router-link> -->

            <br>
            <ul class="post-detail">
              <li>
                <span class="icon-date-icon ico"> </span>
                <span class="bold">Fecha: </span> {{ dmy(ev.evento_fecha) }}
              </li>
              <li>
                <span class="fa fa-map-marker"> </span>
                <span class="bold">Lugar: </span>{{ ev.evento_lugar }}
              </li>
              <li>
                <span class="label">EVENTO </span>
              </li>
            </ul>

            <h2>
              <router-link :to="'/detalleEvento/' + ev.evento_id">
                {{ ev.evento_titulo }}
              </router-link>
            </h2>
            <!-- <p>Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry's standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. It has survived not only five centuries, but also the leap into electronic typesetting...</p> -->
            <router-link
              :to="'/detalleEvento/' + ev.evento_id"
              class="read-more"
            >
              <span class="icon-play-icon"> </span>Leer más
            </router-link>
          </li>
        </ul>
      </div>

      <div class="text-center">
          <ul class="pagination blue">
            <li class="pagination-arrow disable">
              <a href="#" aria-label="Previous" @click.prevent="pag != 1 ? (pag -= 1) : ''">
                <span aria-hidden="true">
                  <i class="fa fa-angle-left"
                    aria-hidden="true">
                  </i>
                </span>
              </a>
            </li>

            <li v-for="(i, index) of pager" :key="index">
              <a href="#" :class="[i == pag ? 'active' : '']" 
              @click.prevent="pag = i">
                {{ i }}
              </a>
            </li>

            <li>
              <a href="#" aria-label="Next" 
              @click.prevent="pag != pager ? (pag += 1) : ''">
                <span aria-hidden="true">
                  <i class="fa fa-angle-right" aria-hidden="true">
                  </i>
                </span>
              </a>
            </li>
          </ul>
        </div>

      </div>
      <!-- End Left Column -->

      <!-- Start Right Column -->
      <div class="col-sm-4">
        <SidebarCustom />
      </div>
      <!-- End Right Column -->
    </div>
  </div>
</template>

<script>
import SidebarCustom from "@/components/SidebarCustom.vue";
import { mapState } from "vuex";
export default {
  name: "EventosView",
  data() {
    return {
      Eventos: [],
      search: "",
      searchGet: false,
      searchValues: [],

      NUM_RESULTS: 4,
      pag: 1,
      pager: 0,

      //------
      tipo: "",
      Convocatorias: [],
    };
  },
  computed: {
    ...mapState(["url_api", "getter"]), //===getter
  },
  components: {
    SidebarCustom,
  },
  methods: {
    async getEventosAll() {
      try {
        let res = await this.axios.get(
          "/api/eventoAll/" + process.env.VUE_APP_ID_INSTITUCION
        );
        this.Eventos = res.data;
        this.pager = this.Eventos.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    async getTipoConv(tipo_conv) {
      //===
      try {
        let res = await this.axios.get("/api/Tipoconvocatorias/" + tipo_conv);
        this.tipo = res.data.Descripcion.tipo_conv_comun_titulo;
        this.getConvocatorias();
      } catch (error) {
        console.log(error);
      }
    },
    async getConvocatorias() {
      //===
      try {
        let res = await this.axios.get(
          "/api/convocatoriasAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Convocatorias = [];
        res.data.forEach((cca) => {
          if (
            cca.con_estado == "1" &&
            cca.tipo_conv_comun.tipo_conv_comun_titulo == this.tipo
          ) {
            this.Convocatorias.push(cca);
          }
        });
        this.pager = this.Convocatorias.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    clickBack() {
      //===
      this.$store.commit("clickLink");
      this.$router.go(-1);
    },
    dmy(fecha) {
      const meses = [
        "enero",
        "febrero",
        "marzo",
        "abril",
        "mayo",
        "junio",
        "julio",
        "agosto",
        "septiembre",
        "octubre",
        "noviembre",
        "diciembre",
      ];
      let fechaCadena = fecha.substr(0, 10);
      let fechaArray = fechaCadena.split("-");
      return (
        fechaArray[2] +
        " de " +
        meses[parseInt(fechaArray[1]) - 1] +
        " de " +
        fechaArray[0]
      );
    },
    buscar() {
      if (this.search != "") {
        this.searchGet = true;

        this.searchValues = [];
        this.Eventos.forEach((evento) => {
          if (
            evento.evento_titulo
              .toUpperCase()
              .includes(this.search.toUpperCase())
          ) {
            this.searchValues.push(evento);
          }
        });
      } else {
        this.searchGet = false;
      }
    },
  },
  mounted() {
    this.$store.commit("loadOn");
    this.getEventosAll();
  },
  created() {
    this.$store.commit("loadOn");
    this.getEventosAll();

    this.getTipoConv(this.$route.params.tipo_conv); //=======
  },
};
</script>
